服务：态度好', '2024-09-11', 5, '[''卫生状况'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234d12000fi6hwa42562_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231o12000fi6gjxu7BBB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务很好，环境舒适宜人，值得入住！', '服务很好，环境舒适宜人，值得入住！', '2024-10-06', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231812000g0f456b6820_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231q12000g0felxc6E41_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234u12000g0f0uya1C6D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店虽老但服务还是很好，rose', '酒店虽老但服务还是很好，rose', '2024-10-08', 5, '[''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232f12000g1fusbi2E59_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '行政酒廊 Cathy 和 Echo 服务很好，希望行政酒廊食物种类可以更丰富。还', '行政酒廊 Cathy 和 Echo 服务很好，希望行政酒廊食物种类可以更丰富。还有回访的小颖态度很赞。整体体验感很不错。', '2024-09-14', 5, '[''餐饮设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236k12000fk0sqts0799_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0235612000fk0omgeC335_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233c12000fk0t92v59D5_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常好的体验，老牌的星级酒店，服务态度很好，很多外国友人入住，位置不错！总体感觉', '非常好的体验，老牌的星级酒店，服务态度很好，很多外国友人入住，位置不错！总体感觉很好，体验感很好！满意！', '2024-08-08', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236c12000f1lies8CB1E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233t12000f1led1vE69F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234b12000f1lfxo292C1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌5星级饭店，房间有点年代感，但还是很干净，服务是真的好，从前厅到客房和餐厅，', '老牌5星级饭店，房间有点年代感，但还是很干净，服务是真的好，从前厅到客房和餐厅，遇到的每一个服务生都很亲切，很有礼貌，4楼的博物馆记录了广州酒店的发展历程，值得一看', '2024-06-10', 5, '[''前台服务'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235112000eexnpdrE6B9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230212000eexdy0eCCEF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231012000eexdwl7FEDA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '暑假带孩子去长隆，长隆附近的酒店都涨到住不起了，所以选择了住花园酒店，老牌五星级', '暑假带孩子去长隆，长隆附近的酒店都涨到住不起了，所以选择了住花园酒店，老牌五星级酒店，服务一流，必须五星好评。', '2024-07-24', 5, '[''整体满意度'', ''前台服务'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0232w12000evyma7p3A3B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231312000evym581B6C1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234l12000evynw0z946D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '美丽的花园酒店，广州的国际化大酒店，很美，服务也很好，特意表扬一下酒店的康乐部，', '美丽的花园酒店，广州的国际化大酒店，很美，服务也很好，特意表扬一下酒店的康乐部，游泳池的服务，救生员都有三个，还有酒水部，迎宾，送水送毛巾，救生员小周热情服务，讲解，让客人游泳的很安心，餐饮服务都很好，特别行政酒廊30楼的金牌导游CARRIE，没在服务时间帮我女儿做了咖啡，端午节早餐人有点多，也只等了10分钟，吃完后还有经理来道歉，服务不周，很是感慨酒店服务人员的素质，
但我这里重点说一下前台服务，希望管理层能看到，前台是我这次住店体验不好的，工作人员没有认真看订单，先分配我去9楼房间，我的订单是18楼以上的，吃完饭一看不仅楼层低，还是尾房，后来交涉后给升级了，过程就不说了，其实最终还是住的升级房型，你一早给我不是不用这么麻烦，因为我也是你们金卡会员，在办理入住的时候看到柜台堆满了一支一支的康乃馨，是送给客人的，给我办理的工作人员没有任何触动，就在她手边。
大堂的迎宾小姐姐还会主动帮客人拍照，很美的酒店，希望前台能看到，不要给酒店拖后腿。', '2024-06-15', 4, '[''前台服务'', ''公共设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233q12000ehd9s634411_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232512000ehdbnpq07B9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231v12000ehd8uj4D165_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间干净卫生，超喜欢后花园，忘了拍照，还参观了4楼的博物馆，服务态度不是一般的好', '房间干净卫生，超喜欢后花园，忘了拍照，还参观了4楼的博物馆，服务态度不是一般的好，在酒店吃了早餐和晚餐，菜式丰富，根本没办法一一品尝，非常满意，下次过来还会选择花园酒店', '2024-06-06', 5, '[''整体满意度'', ''餐饮设施'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0200v12000ecnhcj491A5_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0236q12000ecndo8v7249_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233w12000ecmodmw7803_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234x12000ecn0sciF7A0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州的老牌酒店！各方面都还是不错！房间不算大，但布局还算合理。后花园是酒店的亮点', '广州的老牌酒店！各方面都还是不错！房间不算大，但布局还算合理。后花园是酒店的亮点，荔湾亭点心出品也是不错的！', '2024-09-28', 4, '[''整体满意度'', ''周边配套'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230312000ft5qzct8B64_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236o12000ft5pgz0B6DA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000ft5db3lA7C6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌五星级酒店，还是很能打的，性价比高！离地铁非常近，离利苑近！酒店金碧辉煌的，', '老牌五星级酒店，还是很能打的，性价比高！离地铁非常近，离利苑近！酒店金碧辉煌的，很多老外，周边很多印度餐厅??', '2024-08-13', 5, '[''性价比'', ''交通便利性'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0235z12000f3q5d3w490C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232n12000f3q0gksA33C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232h12000f3q63f7228E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232w12000f3py6ozCBD0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '位置很好，出行方便，设施，卫生，前台服务也很不错。就是两点瑕疵：门童交接有空档，', '位置很好，出行方便，设施，卫生，前台服务也很不错。就是两点瑕疵：门童交接有空档，下大雨的天气，开车到了，也没人指引停车，接箱子；大堂引导员有点不在状态，不停私语，还望加强培训。', '2024-06-05', 4, '[''交通便利性'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230212000ec065utDC28_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232o12000ec07sniF612_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230312000ec06f4u9A31_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店环境很好，非常干净，服务好', '酒店环境很好，非常干净，服务好', '2024-10-05', 5, '[''卫生状况'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236j12000fzx7qu50D7E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236n12000fzx8q97F7EC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很有文化底蕴的酒店，博物馆超级棒', '很有文化底蕴的酒店，博物馆超级棒', '2024-10-03', 5, '[''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0236w12000fy62fnf40E8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '大堂气派！老牌酒店服务做得就是好，每天都有小惊喜，太贴心了！！自助早餐选择种类很', '大堂气派！老牌酒店服务做得就是好，每天都有小惊喜，太贴心了！！自助早餐选择种类很多，必定有你喜欢??', '2024-07-29', 5, '[''餐饮设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233a12000expvgr04BCD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235812000expq3p464B4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231012000expl8061A77_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234612000expzr1eA69B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234x12000exq6pze8950_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234312000expe2wr1961_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '每次去广州都备注的一个酒店之一，环境不错，就是房间小一点，周围购物方便，去任何一', '每次去广州都备注的一个酒店之一，环境不错，就是房间小一点，周围购物方便，去任何一个地方也很方便，最喜欢的就是酒店的花', '2024-09-04', 5, '[''周边配套'', ''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231712000fe6jhws5195_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234z12000fe67pkmAA23_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236512000fe69sfeA98E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231u12000fe64twf7A01_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235l12000fe62fel6C88_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234112000fe6itpo2510_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233x12000fe6fc7kFF65_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230v12000fe68gh277AA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '是什么好运让我在广州暴雨天气入住了花园酒店～', '是什么好运让我在广州暴雨天气入住了花园酒店～
没有亲眼目睹花园酒店的瀑布后花园有点遗憾，
但其他都是很棒的体验～

所选的区域位置比较市中心，
无论去广州塔还是去沙面岛玩耍
居中的位置出行都比较方便。

大堂看着有点奢华，
一楼有瀑布餐厅以及下午茶??
定了两间双床和大床，
虽然是一样的价格，但大床房带浴缸
备好泡泡浴球可以带娃洗个泡泡浴??

早餐就是比较中规中矩的自助餐，
但点心这块很是吸引甜品爱好者～

下次来还是会住这里，希望可以天公作美～', '2024-04-21', 5, '[]', '["[ \"https://dimg04.c-ctrip.com/images/0234112000dqrp8b3A0C3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235812000dqs35ub817F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234y12000dqrygc265ED_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236e12000dqrm9ffD140_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236n12000dqrv7zo8D09_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236y12000dqrtm9v3856_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230t12000dqrrlmy5FD4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236912000dqrvets4948_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236b12000dqs07tl3A28_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店位置出行方便 虽然是近40年前开业的第一批五星级酒店 但是并不觉得老旧 房间', '酒店位置出行方便 虽然是近40年前开业的第一批五星级酒店 但是并不觉得老旧 房间面积大分区合理 健身房设施齐备 后花园颇有岭南园林神韵值得一观 行政酒廊在顶层旋转餐厅 服务细致热情 唯一小缺憾是房间香氛有点类似于阿拉伯特点 略微不适应', '2024-05-12', 4, '[''交通便利性'', ''公共设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236t12000dz097al8949_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236412000dz06gndBBA3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233612000dz06praC769_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233q12000dz09bzt952F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236y12000dz0chok2283_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234h12000dz0arewE72C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州和南沙两家花园酒店都住了，自助晚餐都做得很一般，没啥好吃的，三文鱼质量也不行', '广州和南沙两家花园酒店都住了，自助晚餐都做得很一般，没啥好吃的，三文鱼质量也不行，这个房价实在性价比不高', '2024-08-27', 4, '[''性价比'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233912000f9r8nprDD39_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237212000f9rbeufE2C7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234312000f9r0v091B76_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店环境非常棒，去各个景点都很方便，房间也干净，服务贴心，因为办理了续住，酒店还', '酒店环境非常棒，去各个景点都很方便，房间也干净，服务贴心，因为办理了续住，酒店还送了早餐，非常满意的一次体验', '2024-07-21', 5, '[''整体满意度'', ''交通便利性'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0234a12000euq7y18E6A7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很满意的一次住宿，环境好，早餐品种很丰富，一楼瀑布餐厅，三楼中餐厅，还有三十楼的', '很满意的一次住宿，环境好，早餐品种很丰富，一楼瀑布餐厅，三楼中餐厅，还有三十楼的行政酒廊，Carrie和Echo二位小姐姐很专业又很有礼貌，推荐，推荐', '2024-09-17', 5, '[''餐饮设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233812000fm1dhv84875_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231012000fm1l9m63978_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234c12000fm1n2p39706_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境：优美 ', '环境：优美 
服务：好????', '2024-10-08', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231u12000g1o6tn50BC4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很不错，服务也很到位。很有年代感的一家酒店，下次来还会光顾', '房间很不错，服务也很到位。很有年代感的一家酒店，下次来还会光顾', '2024-08-28', 5, '[''整体满意度'', ''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231512000faf0qm8BF9E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000faemxpb50A8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233n12000faf0qe3E851_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '定的大床房，给升级了套房，套房的面积比大床房大一倍，没有到酒店之前很忐忑，因为看', '定的大床房，给升级了套房，套房的面积比大床房大一倍，没有到酒店之前很忐忑，因为看到评论说因为酒店旧所以有霉味，到了房间之后发现完全是多虑了，房间一点味道也没有，地理位置也很棒，打车去各景点大概都在30元以内，出酒店门就是地铁，周边吃的也很多，很多热门的店周边都有分店。这次住的很满意。', '2024-05-09', 5, '[''整体满意度'', ''交通便利性'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0233m12000dxetxw3824B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234512000dxetq2t63C0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店位于城市市中心很方便，酒店的花园也很漂亮，服务也很好，大堂非常的华丽，?', '花园酒店位于城市市中心很方便，酒店的花园也很漂亮，服务也很好，大堂非常的华丽，?酒店大堂的花园大使小何服务很不错??', '2025-04-05', 5, '[''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231g12000jkt9idsDCE1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q12000jkvevqu3D7B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前台Zara和Viria的接待很热情，免费赠送了小朋友早餐。分别体验了一楼瀑布餐', '前台Zara和Viria的接待很热情，免费赠送了小朋友早餐。分别体验了一楼瀑布餐厅和30楼的旋转餐厅。', '2024-07-31', 5, '[''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0237112000eyg3oyvD274_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店环境好 很好看的酒店', '酒店环境好 很好看的酒店', '2024-12-15', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236812000h7w419cA60D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235i12000h7w54971E27_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231812000h7w5xby4290_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '淘金地铁站出来就是，但是门前交通不太方便，车进酒店要等很久。景观一般。设施是不错', '淘金地铁站出来就是，但是门前交通不太方便，车进酒店要等很久。景观一般。设施是不错的，还有咖啡机，床比较大。', '2024-08-08', 4, '[''交通便利性'', ''房间设施'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0232p12000f1iua68D2F8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234z12000f1j4a88ED4A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237012000f1j2x9034BE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234312000f1jixjm58A2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '跟我前一天的天差地别，前台帮我办理入住的礼宾也非常富有笑容和专业，全程微笑。价位', '跟我前一天的天差地别，前台帮我办理入住的礼宾也非常富有笑容和专业，全程微笑。价位适中，值得再次入住', '2024-07-21', 5, '[''前台服务'', ''性价比'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234712000euodzsiDC77_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234012000euoeeu1CAC6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q12000euodu0k0685_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一路风雨来到广州，毕竟有悠久的历史，从城到人到酒店从美景到美食都丰富而厚重。', '一路风雨来到广州，毕竟有悠久的历史，从城到人到酒店从美景到美食都丰富而厚重。
房间免费升级行政套房，17岁的少年免费加床，花园饭店真的有温暖到我，房间的细节让，辉煌的大堂，让多年来游历29国的我第一次感觉到宾至如归，结合国外很多博物馆的展品，终于明白了，他们当年为何那样推崇中国元素的装修。
床很舒服，布局合理，枕头可选择，香皂很香，拖鞋很软，自动窗帘方便又遮光，灯光很舒适，忘带房卡也不怕去，电梯口总有热情美丽的服务员。
地铁淘金站的旁边，地处越秀老城区，繁华方便，到各个景点都很方便，外国门童帮忙开门时，心中很骄傲，民族自豪感。
花园酒店让我的广州之行幸运，圆满，非常完美的入住体验，五星推荐！', '2024-05-06', 5, '[''整体满意度'', ''房间设施'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0234r12000dw8f86oF987_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232912000dw8b2wp57B0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233i12000dw80ttu48CC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店是老广心中机具代表性的酒店，从小就对酒店有着特殊的情感，今天终于有机会体', '花园酒店是老广心中机具代表性的酒店，从小就对酒店有着特殊的情感，今天终于有机会体验一次，房间做了升级，套房空间大，环境卫生可以，本次出行满意', '2024-06-16', 5, '[''整体满意度'', ''房间设施'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0233a12000ehr67dgEACD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234t12000ehr5tk4384C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232u12000ehr62asB44C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233n12000ehr6cmmF20E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235b12000ehr69s836A3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常喜欢这家，每次来广州只选花园，服务和交通便利没话说，??', '非常喜欢这家，每次来广州只选花园，服务和交通便利没话说，??', '2024-08-29', 5, '[''前台服务'', ''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236k12000fasuzin5F0A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000fat7qt8C7EF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '位置:越秀区中心位置，近地铁，出行就餐方便。', '位置:越秀区中心位置，近地铁，出行就餐方便。
惊喜:感谢前台艾薇儿，赠送了三份早餐，升级90平行政套房。风景绝佳，体验不俗。
氛围营造:文化气息浓郁的大堂，国风雅韵buff，春节还有室内庙会，年味浓郁。
服务:春节期间，实习生过多，有些跟不上，可以理解。
用餐:场地小，西餐偏多，喜欢粤式早茶的请飘过。
总体:老国产五星级，有自己的调性！', '2025-01-29', 5, '[''交通便利性'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235w12000i5avcz3470E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236112000i5ba4l67E26_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231k12000i5bw0hgFCB2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233h12000i5aqvur59D0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '到酒店时间晚，感谢前台小姐姐安排了满意的房间和延迟退房。每次到广州都住花园酒店，', '到酒店时间晚，感谢前台小姐姐安排了满意的房间和延迟退房。每次到广州都住花园酒店，漂亮，卫生、服务好、出行方便。5??赞赞赞', '2024-12-18', 5, '[''前台服务'', ''整体满意度'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0233z12000h9l85leD65B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230d12000h9lcxopD6F1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店服务太差了，整个过程是，在酒店打印资料费20元，我提出放房费一起结算，工作人', '酒店服务太差了，整个过程是，在酒店打印资料费20元，我提出放房费一起结算，工作人员说只能现场支付。现场支付了20，最后结帐酒店又从押金中扣，两次投诉才拿回20元，整个过程匪夷所思，难道只有二次付款才能从押金里扣吗？！现场支付后工作人员不进行标注的吗？！区区20元，费的心力远不及此。更气的是住3天花将近5千，发票只开了1128元，莫名其妙的各种错！作为五星酒店的基本服务能力在哪里？！', '2024-05-07', 3, '[''前台服务'', ''退房/入住效率'', ''价格合理性'']', '["[ \"https://dimg04.c-ctrip.com/images/0232a12000dwiyz6v6EF5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店服务体验非常好，可以说是感动式服务，酒店注重服务细节和用户体验，主动', '广州花园酒店服务体验非常好，可以说是感动式服务，酒店注重服务细节和用户体验，主动为客户提供超值的升级服务，从迎宾、接待、客房到环境和配套都名副其实，再次到广东还想入住花园酒店，感谢酒店管理者和服务人员的辛苦付出和优质服务，你们完全能代表中国五星级酒店品牌和形象！', '2024-05-08', 5, '[''前台服务'', ''整体满意度'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232q12000dwz2wpd7912_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231x12000dwz4561E5DA_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231312000dwz3m5tD903_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌酒店的品质保证，第一次入住花园酒店，感觉很贴心，免费升级了套房，送了入住果盘', '老牌酒店的品质保证，第一次入住花园酒店，感觉很贴心，免费升级了套房，送了入住果盘、小孩洗漱套装、冰箱贴、手绘地图，还给小朋友送了一只小羊玩偶，特别可爱。酒店虽然有点年份，但整体还是干净整洁，大堂很华丽，很多广州的装饰，还有一个博物馆可以了解酒店的背景和文化。瀑布餐厅氛围感很好，可以看到花草繁茂的后花园和流水瀑布。整体服务很到位，客房、餐厅都有充足的服务人员，前台的Mancy和James特别nice，有种宾至如归的感觉。', '2024-07-28', 5, '[''前台服务'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0232q12000exblzpj3E7F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235h12000exbmjue74CE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232m12000exblcb42750_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231312000exblj30B4F3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236o12000exbjrjy83AC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000exbkgcd61DA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232v12000exblpv9FD21_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店环境优美，瀑布餐厅和后院的小花园都很有特色，工作人员服务热情，房间干净卫生，', '酒店环境优美，瀑布餐厅和后院的小花园都很有特色，工作人员服务热情，房间干净卫生，稍小设施也有点老旧。早餐非常丰富，还有很多外国人，总体还是非常不错的。', '2024-08-16', 4, '[''餐饮设施'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0237012000f56syto175E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230j12000f56wmryD338_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233t12000f56w3ej4F59_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务非常好！里面的餐也很正宗，地理位置很好，地铁站出口就是，很方便！适合带孩子！', '服务非常好！里面的餐也很正宗，地理位置很好，地铁站出口就是，很方便！适合带孩子！', '2024-08-04', 5, '[''交通便利性'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234l12000f02o4etAB56_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232t12000f02rruzD406_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235312000f02nhwyBD2E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236c12000f02jv4l391E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236c12000f02iecu70EC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235312000f02mqu50168_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232212000f02j4y3D7CE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236l12000f02idxgDA33_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '来过很多次了，这边的人气跟地理位置都让我很喜欢，也是一个非常有老广气息的酒店，这', '来过很多次了，这边的人气跟地理位置都让我很喜欢，也是一个非常有老广气息的酒店，这边也有挺出名的餐厅，还有一进门就能见到身穿金色衣服的小姐姐，交谈过后发现他们原来是花园白金大使，让我印象深刻的是一个叫小何的大使，服务真的很不错??', '2025-03-30', 4, '[''前台服务'', ''周边配套'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234l12000jf4g5en1CC8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234412000jf4k8gw8A04_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很好，适合小朋友，还有小朋友拖鞋牙刷，打电话给前台，送来的非常快。还有铅笔橡', '房间很好，适合小朋友，还有小朋友拖鞋牙刷，打电话给前台，送来的非常快。还有铅笔橡皮尺子卷笔刀。小胶棒，小羊商铺ADA LINA 迎宾LIVEN 都很好。来之前看到很多差评，有点忐忑，但是来了之后，很好。小朋友说非常好，酒店特别大', '2024-05-01', 5, '[''房间设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235i12000duj0gdc88B2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234h12000duiom9v04B2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231212000duirimu909A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232e12000duj0qyh83F2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230212000duirea34067_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '91年的时候路过花园酒店，觉得好高端好大气，就非常想去，各种阴差阳错，一拖就拖到', '91年的时候路过花园酒店，觉得好高端好大气，就非常想去，各种阴差阳错，一拖就拖到了30年后。后花园，锦鲤酒吧感觉都非常好，早餐是在旋转餐厅吃的，风景不错，还非常丰盛，牛腩也很好吃。前台服务很好，很热情，回访的小晴态度也很好，值得表扬，有机会一定再来。', '2024-09-12', 5, '[''餐饮设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235e12000fil8dnd93CD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q12000fikq31e7D2B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232d12000fil2y3309E9_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '大堂美轮美奂，瀑布餐厅震撼。太喜欢花园酒店了', '大堂美轮美奂，瀑布餐厅震撼。太喜欢花园酒店了', '2024-09-08', 5, '[''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236c12000fgkrl9b4FAD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230g12000fgk0plp6854_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间设施很好，餐饮很精致，服务员很多，随时出现在你需要的时候。', '房间设施很好，餐饮很精致，服务员很多，随时出现在你需要的时候。', '2024-08-22', 5, '[''房间设施'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230e12000f7cu8m9A5A4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间干净整齐，服务很棒。环境配得上五星级，后花园飞瀑流泉，游鱼欢悦，绿树蓬蓬。酒', '房间干净整齐，服务很棒。环境配得上五星级，后花园飞瀑流泉，游鱼欢悦，绿树蓬蓬。酒店建筑设计更是独到有文化韵味。', '2024-06-25', 5, '[''整体满意度'', ''卫生状况'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232r12000ekih86o2849_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232p12000ekigx8e6009_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236112000ekif2lzCBD3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235h12000ekih2gr3342_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235l12000ekiah8mC0D4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232b12000ekif4z4DFE5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236e12000ekier2g1946_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233f12000ekijjneFDFB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231212000eki3z02BF81_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌五星级酒店，虽然有将近四十年了，但内部装修风格和质感比大部分现在新的酒店都好', '老牌五星级酒店，虽然有将近四十年了，但内部装修风格和质感比大部分现在新的酒店都好多了，环境不用说，对得起花园酒店的名字，服务不知道是不是广交会的缘故，住的几天都特别好，早餐分别吃了30楼旋转餐厅和一楼瀑布餐厅的，东西差不多，都很丰富，总体对这几天的入住很满意', '2024-05-02', 5, '[''整体满意度'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236w12000dumf8rxCDCF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231e12000dulxq14CC90_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232p12000dumpl127C28_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店的环境真的没话说，不愧是老牌酒店，大厅富丽堂皇；', '酒店的环境真的没话说，不愧是老牌酒店，大厅富丽堂皇；
唯一的缺点就是房间有点点小，但整体房间设施都不错，干净、舒服。', '2024-09-22', 5, '[''房间设施'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0234d12000fouysvj71C8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231112000fouv2q6E87A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '代客户预订，还给升级了房间！客户感觉很满意！今天又续了一天！', '代客户预订，还给升级了房间！客户感觉很满意！今天又续了一天！
作为广州的老五星，服务非常好！连每个楼层都配有服务员指引！厉害厉害！', '2024-06-18', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233212000eicoit5786E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230c12000eicvjwjCE1F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q12000eicylwf62A4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '对海外华人港澳台人来说最知名的内地酒店就是广州花园酒店，非常多外国客入住。位于市', '对海外华人港澳台人来说最知名的内地酒店就是广州花园酒店，非常多外国客入住。位于市中心老城区位置得天独厚，服务也很好，check in等待 会送上可乐饮料。员工积极主动，广交会房间紧张时期酒店还免费给我升级了套房，可能我是携程高级会员的缘故吧，总之非常感谢酒店。', '2024-04-30', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230i12000dtqyyd10B04_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233v12000dtqhh9o4954_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000dtrc8lo1E5C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235112000dtqvg987D7C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232k12000dtqfm2r7FE4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230t12000dtql49eDA5A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235n12000dtqxxgt4D18_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第一次入住白金五星级酒店，全国只有三家，这家服务真的好，服务员是很有包容心的那种', '第一次入住白金五星级酒店，全国只有三家，这家服务真的好，服务员是很有包容心的那种，知道不说破给客人尊荣！那瀑布是绝绝子，让人很迷恋，前厅经理给我们房间升级了套房双床，送了一份早餐，第二天去用早餐，因为一份早餐的原因在30楼旋转餐厅打包两个人享用了，服务员热情的帮我打了包！后来我又去了30楼和1楼另外两个早餐厅，畅通无阻！管理员知道却默许了，让我们很舒服！去了花园博物馆，真的学到了，那份底蕴无需多言处处渗透！在楼层上电梯打开就有服务员热情的送上红茶指引，第二次上去就记得我住的房间，细节到位，下次有机会还会去花园酒店，尝尝米其林餐厅美食，在早餐厅听瀑布声，去花园酒店博物馆里记记酒店发展史！', '2024-05-07', 5, '[''前台服务'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235q12000dwpekw00370_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236012000dwp95l07F67_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p12000dwpe03jEE43_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234v12000dwpdm3i777E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231t12000dwpaut9E75F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q12000dwp9yng0A46_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230h12000dwpda3m7E98_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231t12000dwpas680E38_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232x12000dwpd3zl83B7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '在花园酒店吃住都非常的舒服，花园酒店不愧是花园酒店，酒店的花都非常的漂亮。最让人', '在花园酒店吃住都非常的舒服，花园酒店不愧是花园酒店，酒店的花都非常的漂亮。最让人印象深刻的就是30楼的行政酒廊，这里的风景非常优美，音乐听着也很让人动听。行政酒廊的mignon的笑容很甜美，服务很贴心，ken得服务也非常的周到。让我有一个非常不错的用餐体验，下次旅游还会选择这家酒店。', '2024-04-29', 5, '[''餐饮设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235112000dtkzjm5DA94_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236012000dtkkaye8F09_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000dtl2t61AF00_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '干净卫生，虽然有点旧', '干净卫生，虽然有点旧', '2024-10-08', 5, '[''卫生状况'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235u12000g19nhli375C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234e12000g19v86q6CF3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234v12000g19n1l45F08_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很大 两米大床很舒服 服务很周到 前台送了小朋友早餐 下次还会来', '房间很大 两米大床很舒服 服务很周到 前台送了小朋友早餐 下次还会来', '2024-08-11', 5, '[''房间设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231a12000f32ht1pCFE4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232x12000f32id7rBFC6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000f32bktb93D2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店房间挺大的，一家四口住得下，离地铁站非常近，点外卖也很方便，有酒店后面中国银', '酒店房间挺大的，一家四口住得下，离地铁站非常近，点外卖也很方便，有酒店后面中国银行外卖柜，酒店里还有博物馆值得一看', '2024-07-01', 5, '[''交通便利性'', ''周边配套'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231h12000en289o45C00_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000en2e6l212C8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234n12000en29uy71A9C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233812000en28p6n9C58_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常非常满意的一次入住，酒店就在市中心，离地铁站也近，去哪里都特别方便。特别感谢', '非常非常满意的一次入住，酒店就在市中心，离地铁站也近，去哪里都特别方便。特别感谢Rebecca小钟，看我们又老又小，拖家带口的，主动提供了很多帮助，真心特别满意。行政酒廊的下午茶和欢乐时光我们也特别喜欢。整个酒店有好多外国人进出，非常国际化，还可以喂锦鲤，孩子喜欢的不得了！', '2025-01-19', 5, '[''整体满意度'', ''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236812000hwsat2s65B9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234r12000hwtdgac2A7D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000hwtgdfaCE40_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这个酒店环境美爆了', '这个酒店环境美爆了', '2024-10-05', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234c12000fzlckhg1259_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店位置不错，无论是出游还是觅食都很方便，但是房型实在实在是有点太小了，第一次见', '酒店位置不错，无论是出游还是觅食都很方便，但是房型实在实在是有点太小了，第一次见到一个五星酒店、浴缸和淋浴房局促在小小的一个空间里，确实也是没想到的。。。不清楚是不是广交会的缘故，大堂晚上会有美丽的小姐姐跳舞，贴心的管家小姐姐还帮我们插了鲜花，感恩ing！', '2024-05-04', 4, '[''周边配套'', ''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230f12000dvmr7blB452_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234912000dvmqneh9472_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235l12000dvmrdalD616_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233b12000dvmqvxc18B3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234m12000dvmrdp7E206_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234u12000dvmqvemD7E0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '特别感谢前台小姐姐Ann在我9/22号办理入住时的热情细致的接待', '特别感谢前台小姐姐Ann在我9/22号办理入住时的热情细致的接待', '2024-09-24', 5, '[''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232y12000fqa8sq9A3CE_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233y12000fqa8ss5EBE1_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前台服务态度非常好，办理入住和退房也迅速，生日升级了套房。晚上瀑布自助餐，种类少', '前台服务态度非常好，办理入住和退房也迅速，生日升级了套房。晚上瀑布自助餐，种类少。门口因为兴建地铁，很难去建设六马路。', '2024-07-25', 5, '[''前台服务'', ''退房/入住效率'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0236412000ewapuet4B9E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236v12000ewawj596AD4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235w12000ewanp0g9E78_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '入住两天，感受都还不错，交通也很方便，打车地铁都很便捷。周围美食也很多，广州酒家', '入住两天，感受都还不错，交通也很方便，打车地铁都很便捷。周围美食也很多，广州酒家，点都德，赵记传承～酒店服务非常不错，询问去澳门大巴，服务员会亲自带着走老远到上车的地点！小颜服务热心体贴到位！谢谢她的帮助', '2025-04-03', 5, '[''交通便利性'', ''周边配套'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236z12000jis5dzf8E46_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232i12000jit5qw99D6E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店位置好，出行便利。早餐丰盛服务热情。', '酒店位置好，出行便利。早餐丰盛服务热情。', '2024-09-19', 5, '[''交通便利性'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231u12000fn8lpld7316_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234u12000fn8ai8qBDBD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232p12000fn8lxlk382F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '中秋佳节来广州避台风选择了广州花园酒店', '中秋佳节来广州避台风选择了广州花园酒店
没有额外加价 性价比直接拉满
贝聿铭大师设计的雨棚穹顶充满浪漫感
但更令人惊喜的是酒店服务人员从前台到客房部到餐饮部都热情礼貌管理有素

感谢客房部的Adan和Marry金芳
给予我们整洁安静的客房环境
让我和我的家人宾至如归

感谢行政酒廊的主管Carrie女士
以及她的伙伴Rose、Cathy、Kitty
给予我和我的家人热情舒适的服务

