环境：环境确实没得说，各个餐厅也是非常好
服务：服务非常到位，就是餐厅有额外服务费', '2024-02-11', 5, '[''餐饮设施'', ''卫生状况'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235v12000d6ivxyw2E8C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235z12000d6j17uo5CA5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232j12000d6ize2m7F5D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间非常干净舒适', '房间非常干净舒适', '2024-08-19', 5, '[''卫生状况'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/02352324x8vzgmbx462AF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店年味十足，喜庆气氛满满，餐饮美味服务好。全家在这里渡过愉快的龙年春节，开启顺', '酒店年味十足，喜庆气氛满满，餐饮美味服务好。全家在这里渡过愉快的龙年春节，开启顺利吉祥的新年，非常满意??', '2024-02-16', 5, '[''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235b12000d7vszigB5BC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231z12000d7vsuoy32A7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233e12000d7vt0nh2AFF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237312000d7vszikFD33_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234o12000d7vtaht62B9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233512000d7vszbz2E5B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000d7vtdmuAD70_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231z12000d7vt3ue0C6F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236m12000d7vswuf6F5E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务很好??地铁方便??环境特别美??', '服务很好??地铁方便??环境特别美??', '2024-07-27', 5, '[''前台服务'', ''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234212000ewypi9f400F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231712000ewyq7s42478_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230812000ewymllb9462_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231412000ewymlld2939_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233u12000ewyjmp00608_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230112000ewyendkC21D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '多次来广州出差，都是选择入住广州花园酒店，一进门大堂金碧辉煌，环境卫生管理非常好', '多次来广州出差，都是选择入住广州花园酒店，一进门大堂金碧辉煌，环境卫生管理非常好，房间设施设备也非常齐全，特别谢谢前厅部副经理 吴灵伶，服务很热情，虽然是第一次见面，但是微笑热情洋溢，给人一种如沐春风的感觉，为她点赞??', '2025-03-06', 5, '[''前台服务'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0233p12000iwy8eqjDEA1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000iwydyuv7CE3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233i12000iwwfr5qB533_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232612000iwy63htC591_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店位于市中心，门口就是地铁淘金站，对面是白云宾馆。交通非常便利。', '酒店位于市中心，门口就是地铁淘金站，对面是白云宾馆。交通非常便利。
酒店有六间餐厅，吃东西很方便。酒店花园不算特别大，有两个大瀑布，庭院，假山，小桥，流水，非常惬意。酒店的电梯运行很快，很稳，不需要等很久。j订的红棉套房还包括五百块酒店餐厅消费券，可直接使用，很方便。房间装潢虽然有年代感，但使用起来没有任何问题。
床偏软了点，平时睡惯了硬床，有点不习惯了。
早餐的瀑布餐厅比较小，要排队，建议早点去
前台办入住时等了不少时间，效率稍微差点。
另酒店的博物馆值得去刷一下，有免费讲解。', '2023-11-22', 5, '[''交通便利性'', ''周边配套'', ''退房/入住效率'']', '["[ \"https://dimg04.c-ctrip.com/images/023222215h3zsm4hs69F4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236m2224x7cyp3dc56A3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/023662234daq4s9yo9DFF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236k2234daq4shog76C8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235f2234daq4spe84600_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234w2215h3zsnesg3E81_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p2215h3zsnesh5ED4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235f2234daq4t4tsBC48_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232l2215h3zso1xs7FB0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常满意，因为飞机延误了房务小何还帮我们申请延迟了退房，游泳池小孩也特别开心，下', '非常满意，因为飞机延误了房务小何还帮我们申请延迟了退房，游泳池小孩也特别开心，下次来广州还住这里，棒棒哒！', '2024-06-09', 5, '[''前台服务'', ''公共设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235x12000eebverv47EB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230w12000eebxno12AA7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232812000eebp0fa3A58_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236b12000eec2a0b5C0A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231r12000eebvnsb608B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '除了办理入住的时候特别慢，其他服务都很不错', '除了办理入住的时候特别慢，其他服务都很不错
果然是老牌五星级，各种服务还是很到位的！送的生日小点心也好看又好吃！
而且花园酒店里面拍照也好出片，配上我的马面裙好好看！
瀑布餐厅：照片真的很好看，随便拍拍都好看，但早餐品类太少了，是我吃过五星级餐厅里面少的可怜的了，厨师连蛋卷都煎不好，差评！
荔湾亭：个人感觉名不符实了，价格的确高，菜量实在小，重点是问题只能说是平平无奇，就很正常的味道，没有惊艳之处。', '2023-12-03', 5, '[''前台服务'', ''退房/入住效率'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232u12000coapd6sF694_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231m12000coatg6g5BBB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232w12000coas4o6FC55_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234w12000coas3ku1065_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233c12000coatkc12721_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236n12000coasrfnA2D0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230k12000coavang0BC6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231j12000coal2yh35AF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234m12000coapd6v5AC4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '交通很方便，楼下就有地铁，叫车也很方便，酒店服务员很多，都很热情。记得不要错过瀑', '交通很方便，楼下就有地铁，叫车也很方便，酒店服务员很多，都很热情。记得不要错过瀑布花园，漫步一下很漂亮，小朋友可以带点面包或饼干喂鱼哦！', '2024-02-20', 5, '[''交通便利性'', ''周边配套'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230d12000d92nq1n97AF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233m12000d939xa4E414_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常满意！前台小姐姐Sara还是Cara人真的很好，下次出行还会选择该酒店！', '非常满意！前台小姐姐Sara还是Cara人真的很好，下次出行还会选择该酒店！', '2024-08-31', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230u12000fby6c959FCD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '有回家的感觉，休息得很好', '有回家的感觉，休息得很好', '2024-06-03', 5, '[''整体满意度'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236r324x8v34es8951A8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02309324x8v34es8aC377_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '总体来说有达到期望 甚至超乎想象 花园酒店经久不衰  地铁就在门口 这点非常重要', '总体来说有达到期望 甚至超乎想象 花园酒店经久不衰  地铁就在门口 这点非常重要 广州酒家也在马路对面 但花园酒店的桃园馆更胜一筹（如果不考虑价格） 房间不大 我原来定的花园大床房 前台为了让我及时入住换成新装修的低楼层房间 会看到修路工地 这点比较失望 还有浴室设计偏小 私密性较不足 其实浴缸可以不要设置 对两人入住的不中用 洗脸盆就在离床头不远 无遮拦 如果一人先起床 还是会影响 可以忽略 早餐很丰盛 服务很好', '2024-01-03', 5, '[''交通便利性'', ''周边配套'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231x12000cusxhg2E850_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235812000cusuka67DE2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230612000cusw4kn6AE0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236f12000cusuib750FD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234h12000cusvy2c20F1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232z12000cusyeve948E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230v12000cusubjyE907_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230j12000cuslwhrF849_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232512000custti9850C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店门口是5号地铁线，公交车也很多，附近吃的有陶陶居和点都德，酒店里面有个早茶很', '酒店门口是5号地铁线，公交车也很多，附近吃的有陶陶居和点都德，酒店里面有个早茶很好吃桃园馆
，酒店大厅有颗大大得圣诞树小朋友很喜欢，外面有个后花园。
低层楼电视机无法投屏，房间里灯不是很亮，浴缸很大，外出一天可以给孩子泡澡', '2024-01-01', 5, '[''交通便利性'', ''周边配套'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232l12000cudr81m4B26_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233512000cuds9i5FD1A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236212000cudpbtvA070_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235g12000cudn3qy6F91_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236h12000cudt90e79BB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236312000cudqphd4AE9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000cudu1rl5324_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌五星酒店，设施确实有些老旧了，房间小也确实小，有些日式的设计感。门口迎宾服务', '老牌五星酒店，设施确实有些老旧了，房间小也确实小，有些日式的设计感。门口迎宾服务素质参差不齐，有一个歪果仁迎宾似乎不太主动，看着我们抱着娃拎着箱子和小推车上台阶，也不会主动过来帮我们。其他服务员都非常热情，非常友好且主动。有个做气球的服务生非常会逗小朋友开心。
瀑布花园设计很值得一看，池子里的锦鲤令人心情愉悦，希望好运加持。', '2024-01-05', 4, '[''房间设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235c12000cv78xpj6EA9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233z12000cv766ee36BA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236j12000cv7p7c3FB6D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233z12000cv7mfm1F910_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232912000cv7j91qCC89_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232p12000cv7lbvmA709_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233912000cv7gonyDC60_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231312000cv7ik5mE1A6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '套房非常满意，酒店很有文化底蕴。服务也很好。送入住点心和水果。还送了小羊。就是瀑', '套房非常满意，酒店很有文化底蕴。服务也很好。送入住点心和水果。还送了小羊。就是瀑布的自助餐实在是一般，大年三十588的自助实在是没啥好吃的。', '2024-02-11', 5, '[''餐饮设施'', ''整体满意度'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230o12000d6fji8qE318_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230b12000d6fh3b3A55B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231712000d6fh3b58849_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常满意 服务什么都很好', '非常满意 服务什么都很好', '2024-05-30', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231012000e8jxyq8947F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '刚入住就发现瓜子皮，根本没有服务。空调是坏的。刚进房间就发现马桶也没说。不想评价', '刚入住就发现瓜子皮，根本没有服务。空调是坏的。刚进房间就发现马桶也没说。不想评价了。要是想体验服务和环境的建议别定，不值一千多。唯一亮点可能就是瀑布餐厅。', '2024-01-30', 3, '[''房间设施'', ''卫生状况'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0234b12000d2ylkxtA8CA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236312000d2y6i2g725D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：不愧是白金五星级酒店，酒店大堂非常富力堂皇且浪漫??，设计感超赞。', '设施：不愧是白金五星级酒店，酒店大堂非常富力堂皇且浪漫??，设计感超赞。

服务：老牌的星级酒店服务专业到位，上上下下没一位工作人员都耐心细致，过来庆祝结婚38年纪念的，酒店给升级了房间，前台给了鲜花，房间做了漂亮布置，送了蛋糕，真是惊喜到了，在此感谢每一位用心的工作人员。', '2023-12-30', 5, '[''前台服务'', ''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230q12000ctz1s6o0101_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234q12000ctz3u881A54_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '公共区域设计标准高、用材好，结合了国内传统文化，很前沿，相信多年后也不会落伍。', '公共区域设计标准高、用材好，结合了国内传统文化，很前沿，相信多年后也不会落伍。
酒店内米其林3家，美食很棒！
房间装修及用材有提升空间。', '2024-02-22', 4, '[''公共设施'', ''餐饮设施'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234012000d9otb1m1005_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000d9ou4nbEC3B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233c12000d9of0yt975A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230u12000d9oipezA3A3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧是第一个白金五星酒店，装潢和服务都很棒，适合喜欢探索一下岭南文化的旅行者。唯', '不愧是第一个白金五星酒店，装潢和服务都很棒，适合喜欢探索一下岭南文化的旅行者。唯一美中不足就是房间里面充电的地方不够多，以及吹风机真的很难用，应该提升一下设备便利度，才不愧这么好的环境和服务。', '2024-01-07', 4, '[''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235k12000cvtcgkz4D33_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234y12000cvth3ua123E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232312000cvtdslyCEE7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231l12000cvtf5vg1EC4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店大堂背景很震撼，房间重新装修过，外面花园也很精致；台前巴基斯坦小哥DASTA', '酒店大堂背景很震撼，房间重新装修过，外面花园也很精致；台前巴基斯坦小哥DASTAAN人很nice，普通话流利，有求必应，值得推荐！', '2024-02-19', 5, '[''前台服务'', ''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230512000d8uce936FE9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231k12000d8ucybo2CEA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '白金级酒店真没选错。虽然设施是旧了点，可是老牌星级酒店的服务真是不错，很专业的。', '白金级酒店真没选错。虽然设施是旧了点，可是老牌星级酒店的服务真是不错，很专业的。很喜欢酒店的大厅，红楼梦巨型背景墙好有感觉，酒店的下午茶还行，最好看的就是瀑布背景，设计感超赞。酒店的位置也很好，出门右边就是地铁站，出行非常方便。', '2023-12-29', 5, '[''交通便利性'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235712000ctroyzrBA55_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235j12000ctrq5oo0F6D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000ctrg2q454D8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '又体验了另外的一种房型，虽然老，感觉比新装修的更好，空间高舒适些。各个餐厅也各有', '又体验了另外的一种房型，虽然老，感觉比新装修的更好，空间高舒适些。各个餐厅也各有特色，瀑布餐厅偏西式，精致粤菜料理在桃园馆。老牌米其林的荔湾亭特别怀旧，西关风情浓，菜品精致，不渗假水。4楼的博物馆更是值得看看，珍藏有邓爷爷的墨宝…', '2023-10-31', 5, '[''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230l12000chi0nafC7B3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233m12000chhyp7iBCA1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231i12000chi6fvn7380_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233o12000chhuu37D223_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230d12000chhvp97A2C6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231l12000chhy418132B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234i12000chi3el176FF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235j12000chi5gz3CC85_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231v12000chi5iev32D2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '最大的问题是房间面积小有点旧，服务非常好，大堂金碧辉煌很是气派，后花园的瀑布和环', '最大的问题是房间面积小有点旧，服务非常好，大堂金碧辉煌很是气派，后花园的瀑布和环境是其他广州酒店不能比的，整个酒店到处洋溢着浓浓的春节气氛。', '2024-02-09', 4, '[''房间设施'', ''整体满意度'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235z12000d60ug776CC7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232j12000d60sundDFC5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234e12000d60tq4uEB8C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230k12000d60thpj5963_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前台cookie小姐姐和anna小姐姐接待我们的，一流品质一流服务，浴缸独具风格', '前台cookie小姐姐和anna小姐姐接待我们的，一流品质一流服务，浴缸独具风格，体验感满满，很爱很爱??', '2025-02-24', 5, '[''前台服务'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235512000ipzg5a27D7F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前台接待服务非常热情，酒店设施完善，很好！！！', '前台接待服务非常热情，酒店设施完善，很好！！！', '2024-05-03', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234212000dv8fvz4522C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235u12000dv8lmrfA8CB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '五星级酒店。竞然没有夜床服务、太奇怪了??3天没有一次夜床服务。花园酒店生意太好', '五星级酒店。竞然没有夜床服务、太奇怪了??3天没有一次夜床服务。花园酒店生意太好省下了。第一天入住。2010房、洗澡间的水浸入到卫生间没法使用。换房间后。18 08。从服务员到主管没人对此说一声对不起。哈哈花园酒店牛。????????。', '2023-12-30', 4, '[''客房服务'', ''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233312000ctwbhvmC4EE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231y12000ctwa7i3799A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235r12000ctwa0th7A48_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌5星，感受最深的是，花园想做文创酒店，有自己的博物馆，有古仔讲。床品舒适，早', '老牌5星，感受最深的是，花园想做文创酒店，有自己的博物馆，有古仔讲。床品舒适，早餐建议桃园厅或者荔湾亭，一楼瀑布厅适合外国人的口味，主厨好像是西班牙的，中式茶点比2，3楼差好远。西点OK。', '2024-01-12', 5, '[''餐饮设施'', ''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230z12000cx64iy65988_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231s12000cx5dj6635FE_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '早就久闻花园酒店大名，这次来广州终于有机会入住。酒店到处摆满了鲜花，萦绕在鲜花中', '早就久闻花园酒店大名，这次来广州终于有机会入住。酒店到处摆满了鲜花，萦绕在鲜花中心情很好。最近适逢广交会，办理入住的人稍多，工作人员会准备小饼干和饮料给客人排队间隙等待时享用。感谢前台给我们升级了房型，入住的是粤韵客房。来得匆忙忘带手机充电线了，跟工作人员一说很快就送到了。本来担心浴缸会不干净但是发现自己想多了，卫生搞得还是很不错的。还去了酒店内的博物馆参观，这是一家讲述有关住宿业的博物馆，挺有新意的。酒店环境令人舒适满意，下次来广州还要入住！', '2023-10-31', 5, '[''整体满意度'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0231l12000chmyeza85BC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232d12000chmsk0nDA8A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233c12000chn1ig39658_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233912000chmsk0pBA5F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232d12000chmzent4F62_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231d12000chmtp29FD02_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235212000chn4mteBE61_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234812000chn1ig5D012_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233y12000chmwy3f9CCA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '15:52	携程旅行	4G	', '15:52	携程旅行	4G	
＜	点评详情	
总评分	5.0分	
设施分 5.0	环境分	5.0	卫生分	5.0	服务分	5.0	
2024-07-21发布于广东和家人出游
非常感谢rain小姐姐和客房服务劳拉帮了我们很多忙，妈妈带娃旅游中，给了我们很多帮助。rain还帮我们升级了小羊玩偶。孩子特别开心。劳拉教了我怎么用咖啡机，还帮孩子拿了适合的拖鞋。万分感谢??', '2024-07-21', 4, '[''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235k12000euoxsgb84B5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230r12000eup0g4fF59D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233z12000euozbdr1FBF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233f12000eup0g4lE60E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店位置在市区，位置很好，去附近的景点都很方便。 酒店房间干净，整洁，床品舒服柔', '酒店位置在市区，位置很好，去附近的景点都很方便。 酒店房间干净，整洁，床品舒服柔软， 入住体验非常棒。重点表扬酒店的服务，因为飞机晚点到店时间特别晚，前台小姐姐帮忙升级了房型还延迟了退房； 另外LiVen 热情细致的协助我们解决各种在酒店遇到的问题，真的超贴心。', '2025-04-12', 5, '[''前台服务'', ''整体满意度'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0237412000jqv5xek8E04_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232e12000jqvxz6b345C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235b12000jqwi2aeB014_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234i12000jqvuddv4996_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230112000jqv5xemDFF8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很不错 每位服务人员都非常热情 房型也很好 带上妈妈爸爸和小朋友一起 每个人都很', '很不错 每位服务人员都非常热情 房型也很好 带上妈妈爸爸和小朋友一起 每个人都很开心 小朋友可以喂鱼 爸爸妈妈觉得酒店也很好 准备以后去广州都住这里', '2024-02-04', 5, '[''整体满意度'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232112000d4gbwxaE78E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234v12000d4gpgq14A99_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第二次住花园了，整体环境还是很好的，就是这次行政酒廊搬到了楼上旋转餐厅分出来的一', '第二次住花园了，整体环境还是很好的，就是这次行政酒廊搬到了楼上旋转餐厅分出来的一块地方，感觉还是一楼原来酒吧的位置更舒服还有室外位环境也好，楼上除了晚上能看到一点点广州塔没有什么风景，地方小也显得很局促，不知道是不是心理作用现在下午茶和happyhour没有在楼下时候丰富了，早餐也纯自助了以前在楼下还可以点单的，和一楼的瀑布早餐就没啥差别了。房间还是比较满意的岭客金卡给升了级，
服务：有一天牙疼在休息中午楼上不知道哪里在装修电钻声特别吵，打电话让前台沟通下等我们退房再钻，就这一件事反复打了四五个电话等了半小时才得到解决，本来想待到12点走不得不提前走了，这点让人不是很愉快', '2024-01-01', 5, '[''餐饮设施'', ''安静程度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236d12000cugpn1c1664_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230c12000cugou3t74F8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000cugl0t01831_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店很高大上，入住正是圣诞节，一棵大大的圣诞树??装饰的很华丽。酒店的早餐环境非', '酒店很高大上，入住正是圣诞节，一棵大大的圣诞树??装饰的很华丽。酒店的早餐环境非常有特色，大大的玻璃窗可以看到室外的瀑布，在这里就餐心情愉悦，早餐品种丰富多样，口味也不错??，连住两晚，第二天体验了三十层旋转餐厅的早餐，相比较而言更喜欢一口的环境。只可惜原本的下午茶??，2点退房后不可以享用，白白的浪费掉了，不然，正好吃完下午茶赶往机场都有时间，要是办理入住时提醒一下就好了，算是小小的遗憾吧。', '2024-01-09', 5, '[''餐饮设施'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232712000cwc3agu50AE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233h12000cwc34tcF0CE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230j12000cwc22e27529_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230h12000cwc38qyEFD3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '我们这次是带孩子去广州感受圣诞氛围的，酒店布置很漂亮，孩子也拍了很多美照！带着孩', '我们这次是带孩子去广州感受圣诞氛围的，酒店布置很漂亮，孩子也拍了很多美照！带着孩子去逛了酒店的博物馆，博物馆比较小，但酒店历史都浓缩在其中了！这次过去酒店最不好的体验是旁边在修地铁站，吵到没办法好好休息，晚上吵到十点多，早上不到八点就开工，这是这次出行最最不好的体验了！', '2024-01-21', 4, '[''安静程度'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235c12000czs2u1e664A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233s12000czs5e17033C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234a12000czsjoez1074_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233u12000czs5fn86B65_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235912000czscavf7D00_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常满意的一次住宿，带着爸妈和孩子奔着老牌酒店去的，住了四晚，我们定了两间房，赶', '非常满意的一次住宿，带着爸妈和孩子奔着老牌酒店去的，住了四晚，我们定了两间房，赶上广州降温，还特意给我们升级了套房，服务一级棒超五星体验，谁住谁知道????????', '2024-01-28', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236412000d2aq2b9EF0A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '春节旅程结束最后住花园酒店，体验很好，加钱升级了亲子房房间，小朋友很开心。整体服', '春节旅程结束最后住花园酒店，体验很好，加钱升级了亲子房房间，小朋友很开心。整体服务都不错，唯一不好的是办理入住和早餐需要排队。', '2024-02-16', 5, '[''整体满意度'', ''退房/入住效率'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233y12000d7zi4tgA279_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234r12000d7zhr2199DF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234q12000d7zgb160A9C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236n12000d7zi4u066C7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '干净、周到、环境优美，到处飘着花香，卫生间，床单茶具都非常干净。早餐美味，用餐环', '干净、周到、环境优美，到处飘着花香，卫生间，床单茶具都非常干净。早餐美味，用餐环境好，安静。服务到位。', '2024-03-07', 5, '[''卫生状况'', ''餐饮设施'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230312000dd32ts690EE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232512000dd2by4d1CEE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000dd2yh64DC04_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233x12000dd312ioAF13_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236w12000dd2xsb874A5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间整洁，服务态度好！因为订房时比实际入住房价高赠送了早餐！早餐非常美味！酒店花', '房间整洁，服务态度好！因为订房时比实际入住房价高赠送了早餐！早餐非常美味！酒店花园是真漂亮，花团锦簇，锦鲤小桥瀑布美不胜收。', '2024-02-24', 5, '[''整体满意度'', ''餐饮设施'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230z12000da2ymzbEE4E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235a12000da2y9oeC912_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234s12000da2xyld5E48_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231312000da2yeoeD904_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234m12000da2xgq5FF40_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '因为觉得住的还挺好所以续房一天，酒店正好重新装修一部分房间，让我们搬到粤韵房了，', '因为觉得住的还挺好所以续房一天，酒店正好重新装修一部分房间，让我们搬到粤韵房了，这个房间更新一些，床也更舒适，瀑布餐厅酒店早餐还不错，还赠送了水果，对酒店其他服务还都是很满意的，酒店的博物馆也很值得一看。', '2023-12-24', 5, '[''房间设施'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0204r12000csf2ks81475_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0231i12000csf03so7D2A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232912000cset8ly26F0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000csewtkd9F80_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店位置很好，服务热情周到，春节期间布置的也是非常喜庆，活动很多，还送了鲜花~房', '酒店位置很好，服务热情周到，春节期间布置的也是非常喜庆，活动很多，还送了鲜花~房间干净整洁，床品舒适。早餐在旋转餐厅，还是比较丰富哒', '2024-02-20', 4, '[''整体满意度'', ''房间设施'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234o12000d91cgkm1725_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231n12000d91bhwf13D3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '交通便利，地铁站上来就是北门口。服务人员众多，随时随地都能得到有效的帮助。客房整', '交通便利，地铁站上来就是北门口。服务人员众多，随时随地都能得到有效的帮助。客房整洁干净，布草，洗漱用品，洗澡水压等都令人满意。冲着官方白金五星来的，发现名不虚传。上午到达，前台的南希快速高效的办理了加床加餐的入住，入住后才发现还帮我升级了房型，感谢。客房服务无论是加床，还是我们几次要求送水送用品，其反应速度都是我入住各类高奢酒店以来最快的。早餐的出品可以，员工翻台也是高效。酒店博物馆也值得一观。最后感谢客房服务员拾金不昧，在我自己都没发觉时，值班经理已经联系我，让我的黄金手串失而复得。感谢！', '2024-01-22', 5, '[''前台服务'', ''客房服务'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0231p12000d07p7pi3376_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230w12000d07p2xv9DB0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231e12000d07or8m01D3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234d12000d07p7po6B38_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231s12000d07p2xx7602_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232a12000d07or8o5B7D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000d07p7pu7537_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232o12000d07p2xzC43A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234212000d07or8s7406_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '过年来玩 之前住过一次 这次带爸妈来 这个房型有一个客厅可以加床还蛮适合家庭出行', '过年来玩 之前住过一次 这次带爸妈来 这个房型有一个客厅可以加床还蛮适合家庭出行的 瀑布餐厅服务很好 年夜饭提前预定的桃园馆也很好吃', '2024-02-10', 5, '[''房间设施'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231212000d677jva130D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232e12000d66urw692C5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236r12000d674bfw299D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '时光荏苒，转眼间已是三年之隔，当我再次踏入广州花园酒店的大门，那份熟悉与温馨感油', '时光荏苒，转眼间已是三年之隔，当我再次踏入广州花园酒店的大门，那份熟悉与温馨感油然而生，仿佛时间在这里悄然静止。酒店的服务依旧保持着那份一如既往的高水准，让人丝毫感觉不到岁月的流转。此次入住，我有幸遇到了前台的Niki小姐。她以花园酒店那标志性的热情笑容和细致入微的服务，瞬间驱散了我旅途的疲惫。在得知我是3年前入住过的客人后，Niki更是主动为我升级了房间至粤韵大床房，并贴心地赠送了两份早餐券。这份意外的惊喜，让我对酒店的好感倍增。另外值得一提的是，客房管家LiLi还特意准备了月饼和阳光玫瑰葡萄作为小礼物。这份意外的关怀，让我感受到了家的温暖。三年的时光并未改变花园酒店的品质与魅力，反而让它在我心中更加熠熠生辉。在未来的日子里，我还会再次选择这里，作为我旅途中的温馨港湾。', '2024-07-31', 5, '[''前台服务'', ''整体满意度'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234b12000eyimxt99FA6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230412000eyijk3c2551_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232k12000eyitdkz060C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234m12000eyivnhr670D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236q12000eyimk1vC170_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236j12000eyirguz1918_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店很漂亮 餐厅也多 服务还特别好 不愧是老牌酒店 下次还来', '酒店很漂亮 餐厅也多 服务还特别好 不愧是老牌酒店 下次还来', '2024-04-15', 5, '[''整体满意度'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235h12000dohjzdk737B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很大，不过没有浴缸，淋浴和洗漱区有点小，到不影响房间舒适和整洁', '房间很大，不过没有浴缸，淋浴和洗漱区有点小，到不影响房间舒适和整洁
早餐区域是瀑布餐厅，吃早饭看美景很不错
酒店没有和瀑布，可以去逛逛，没人，景色很美', '2024-01-28', 5, '[''房间设施'', ''餐饮设施'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0230712000d2c65tc2C4F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234b12000d2c9m1n2A75_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230e12000d2c6yopE381_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231m12000d2cadla8220_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店，名副其实，酒店后花园的瀑布庭院还是蛮有气势的。不过酒店确实老了点，客房', '花园酒店，名副其实，酒店后花园的瀑布庭院还是蛮有气势的。不过酒店确实老了点，客房洗手台、淋浴房、卫生间布局感觉很不好，双人房半开放结构有干扰。', '2024-03-03', 4, '[''房间设施'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0230a12000dbzqsch8F1E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234912000dbzrjti79F1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230d12000dbzrvsh7E86_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230w12000dbzr70e2570_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '久违了，花园酒店，20几年前曾经住过，已经渐渐的淡忘了，此次来广州，查到花园酒店', '久违了，花园酒店，20几年前曾经住过，已经渐渐的淡忘了，此次来广州，查到花园酒店已经重新装修与改动了一些房型，便毫不犹豫的订了两晚。

花园酒店绝对的五星酒店中的翘楚，尽管是近40年前的产品，却是生机勃勃，老当益壮。
??论是房间的设施与硬件，都是超五星轻奢酒店标准，二楼的中餐厅环境也是一流的，特别是独特的的岭南风格的后花园（园林），那是人间仙境，白天迷人，夜晚诱人。
美中不足的是，大堂里飘散的香水味，也许选的不对我们的味觉，似乎??点澡堂子的味道，刺鼻而欠舒服。
若能下点功夫，调一下大堂香水味，让更多的客人喜欢，那么，来广州，花园酒店就是第一选择。', '2023-12-19', 5, '[''房间设施'', ''整体满意度'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0204i12000crfm68t5395_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0231w12000crflcx1F60E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234k12000crfm9ca2B74_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233r12000crflaqt3AA7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232l12000crfllao4868_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233n12000crflqvr6298_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234712000crflew11929_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235r12000crfm3otC819_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000crflxao9043_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f12000crfldvyC360_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常满意的一次出游体验，前台Ariel美女给免费升级了套房，房间的欢迎水果质量也', '非常满意的一次出游体验，前台Ariel美女给免费升级了套房，房间的欢迎水果质量也很好，老婆赞不绝口，房间看见花园瀑布，景色很好', '2024-07-23', 5, '[''前台服务'', ''景观/朝向'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230c12000evjt8o2041E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：房间装修设施很好设备很新，房间很大', '设施：房间装修设施很好设备很新，房间很大
环境：酒店内部花园很漂亮，有假山瀑布锦鲤池
早餐很好吃，服务很到位，赠送了30楼行政酒廊的景观和服务都很好', '2024-01-26', 5, '[''房间设施'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0202e12000d1ruhukC2DB_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0233k12000d1roln06434_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232412000d1rcltt686A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州三家白金五星级酒店之一，博物馆详细介绍酒店历史，几乎所有的美女服务人员笑容满', '广州三家白金五星级酒店之一，博物馆详细介绍酒店历史，几乎所有的美女服务人员笑容满面，到处都是，不知为何，上上下下找不到免费入座的地方，连办理入住的地方有没有，老年人长时间站着吃不消。携程网套餐，免费升级到套房，下午茶升级到包含晚上的欢乐时光，非常享受，谢谢！瀑布餐厅自助早餐在上午9点左右竟然排队等候多时，可以学习海花岛酒店分时段就餐方法。花园不是很大，人工瀑布气势磅礴。老外很多，还有外籍服务生。', '2023-12-18', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234e12000cr8khar016B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231a12000cr8b73pF9ED_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233d12000cr8fr6rA484_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230912000cr8gpac2CDE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230612000cr8cfxv1B5D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234a12000cr89l4z75FF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230212000cr8c1vh0785_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很好，升级了个套房，卫生服务各方面都很周到，第一次来，下次还来', '房间很好，升级了个套房，卫生服务各方面都很周到，第一次来，下次还来', '2024-04-02', 5, '[''整体满意度'', ''房间设施'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0233912000dkgcmbt798D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000dkgc8qc958D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店给我的入住体验特别好，走入大堂，映入眼帘是以红楼梦为主题的金碧辉煌的', '广州花园酒店给我的入住体验特别好，走入大堂，映入眼帘是以红楼梦为主题的金碧辉煌的壁画，回眸又见岭南水乡人民生活的生动画面，由于入住的时间离圣诞节很近，节日气氛非常浓郁，入住的客人也特别多，美丽的服务员和蔼可亲，而且心特别细，远远看到客人乘电梯，都会主动为你按好，真正做到客人至上，让人感觉特别舒服。至于它的后花园，绝对有特色，两条18米高的大瀑布从天而降，大气磅礴。因为喜欢，故1月份带着家人再游广州，又订了4晚。', '2023-12-25', 5, '[''整体满意度'', ''前台服务'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236112000csrkwdhF0BE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232312000csrlic6A19E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235v12000csran5a5880_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235n12000csrlzor9562_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店生意很好，接待的先生也很热情、专业。', '酒店生意很好，接待的先生也很热情、专业。
早餐也很不错，丰富而精致
房间布局合理、干净。客房服务有待改善，多要了几瓶水，说是有限制的。1100多元的房费不应该这样', '2024-01-12', 5, '[''餐饮设施'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233c12000cx84h971F48_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231p12000cx838tnDEBA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231812000cx7z86nDBF3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '订的套餐，重新装修后的房间很大，也维持的很新，有JBL信箱，床头有USB插头，两', '订的套餐，重新装修后的房间很大，也维持的很新，有JBL信箱，床头有USB插头，两个洗面盆，17层景观很好，往下能看见瀑布，远景是城市建筑，美中不足的是给我的房间没有浴缸，其他的都很好！早餐后逛一逛瀑布花园很舒服～有机会会再去～', '2023-12-15', 4, '[''房间设施'', ''景观/朝向'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232c12000cqn38w0C3E9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230t12000cqn38ni3E90_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232712000cqn3710700C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235012000cqn2yi5C8F9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235312000cqn3a3k74F2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老贵族一样，尽管有让人不那么称心的地方，但气质非凡，服务规范周到。', '老贵族一样，尽管有让人不那么称心的地方，但气质非凡，服务规范周到。
其实花园酒店完全没必要和别人做比较。', '2024-02-26', 4, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235x12000daozdd7C20E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235h12000daozvn4B292_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233g12000daoz9o971E4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第一次来花园酒店，非常舒适惬意的一次入住，无论服务，环境，卫生，餐食，都很满意，', '第一次来花园酒店，非常舒适惬意的一次入住，无论服务，环境，卫生，餐食，都很满意，尤其酒店设计风格和设施，传统华丽又时尚优雅，下次还会再来！好赞??????', '2024-01-21', 5, '[''整体满意度'', ''房间设施'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230i12000cztyn251C08_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234x12000cztyqqm29BE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231512000cztymy94095_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000cztykbi7019_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237312000cztyph683CD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '建筑格调简洁，装修豪华典雅，房间设施舒适，非常不错，服务诚恳周到', '建筑格调简洁，装修豪华典雅，房间设施舒适，非常不错，服务诚恳周到', '2024-04-02', 5, '[''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233q12000dkfyqaa4476_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234i12000dkfzap19116_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店地理位置不错，离北京路挺近的，早餐非常好吃，连吃两天，非常的满意，下次来广州', '酒店地理位置不错，离北京路挺近的，早餐非常好吃，连吃两天，非常的满意，下次来广州还会继续打卡，花园酒店的花园确实像花园一般，景美鱼肥！', '2024-02-02', 5, '[''周边配套'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231312000d3w2j72A1D0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235312000d3w2i5h2907_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233e12000d3w4k8lBFCB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州老牌酒店，环境很不错，有瀑布花园。服务很好要给赞。早餐很丰富。出门就是地铁站', '广州老牌酒店，环境很不错，有瀑布花园。服务很好要给赞。早餐很丰富。出门就是地铁站。唯一不足就是酒店房间有点陈旧。', '2024-02-20', 4, '[''交通便利性'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230412000d9466fo9DCE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233o12000d94gs7a24C6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231c12000d94in1oF718_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '比预期的好很多，老牌的酒店，原以为设施会老旧，但房间维护的很好，很干净，很温馨，', '比预期的好很多，老牌的酒店，原以为设施会老旧，但房间维护的很好，很干净，很温馨，很有岭南特色。地下停车场有3层，充分满足了停车需求，就是停车场的电梯跟酒店是分开的，要绕过一节路，室外的，刚好下点小雨，自己拖着行李箱带着几个小朋友有点不方便。办入住的时候等的时间有点久，可能人太多的缘故，大堂真的是人来人往，古色古香的感觉，吃饭的、参观的、拍照的、络绎不绝……办入住的时候房间没打扫好，去3楼桃园馆吃了顿饭，正宗的粤菜，摆盘正、味道正，除了价格贵没别的缺点了，推荐大家可以尝试一下。酒店后花园很漂亮，有水池和鲤鱼，还有瀑布，景色怡人，另外还享受了30层的行政酒廊，服务员Ken和Zocy非常热情有礼貌，会主动询问和帮忙，非常感谢他们高水准的服务，总之，花园酒店可以让你更直观的了解广州的一些地方特色和风土人情，值得一住。', '2024-01-29', 5, '[''整体满意度'', ''房间设施'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231312000d2gdevyF7CD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232c12000d2gd0mfA96A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235g12000d2fn5r689A2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233o12000d2fuqpt4FF9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233r12000d2g6fsa74FB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230m12000d2g23q9E9D0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231i12000d2g23qbCF9B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234612000d2g4dy68129_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000d2g2tsbAEAD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '大堂很豪华漂亮，也有过年的氛围，房间稍微小了点。总之很好的住宿体验。到处都很漂亮', '大堂很豪华漂亮，也有过年的氛围，房间稍微小了点。总之很好的住宿体验。到处都很漂亮，而且很有年味，感觉像在自己家过年一样。', '2024-02-11', 5, '[''整体满意度'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231812000d6gsuwuF313_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231p12000d6gt3wy00F5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236112000d6gtd8z57C7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '好好好好好好好好好好好好好好好好好好好好好好好好', '好好好好好好好好好好好好好好好好好好好好好好好好
设施：好好好好好好好好好好好好好
卫生：好好好好好好好好好好
环境：好好好好好好好好好好好好好', '2024-01-22', 5, '[''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0232k224x8tu48mysDDD4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p224x8tu4ayh4234F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235b224x8tu4ayh5E22E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231y224x8tu3wmc113E6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老城区的老牌酒店，去哪里都很方便。过年期间有很多活动，工作服务人员也很多。美中不', '老城区的老牌酒店，去哪里都很方便。过年期间有很多活动，工作服务人员也很多。美中不足的是早餐一般，品种很少，亲子设施少。', '2024-02-12', 4, '[''交通便利性'', ''周边配套'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234212000d6orjs24828_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232u12000d6p9ajx207D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234b12000d6p3dbaF9DB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '续住豪华白金五星花园酒店，环境优美，房间舒适，凌璇阁旋转餐厅非常棒！早餐品种丰盛', '续住豪华白金五星花园酒店，环境优美，房间舒适，凌璇阁旋转餐厅非常棒！早餐品种丰盛，360゜全景欣赏广州风景。', '2024-02-20', 4, '[''餐饮设施'', ''整体满意度'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0237112000d8xo2z3A6C8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231n12000d8xxw43AC7C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235o12000d8xylimA27E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店具有广州特色，尤其大堂非常富丽堂皇，还有花园瀑布小桥流水。酒店周边热闹，', '花园酒店具有广州特色，尤其大堂非常富丽堂皇，还有花园瀑布小桥流水。酒店周边热闹，地铁淘金站就在旁边，购物方便。酒店二楼的中餐厅早茶好吃。毕竟是1985年开业的酒店，房间内部如果重新装修就更好了。', '2023-11-27', 4, '[''周边配套'', ''交通便利性'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236h12000cn85oznFE03_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l12000cn8b7odCF03_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234o12000cn89e51D30F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232j12000cn88tmc12AC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235812000cn84e570FDA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235012000cn87w60519D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236d12000cn8aerc7C05_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233k12000cn86tzqD3E6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234u12000cn8ctpa07AF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌五星酒店，服务、餐饮、卫生、环境都很赞，距离5号线淘金站，几乎零距离，特别适', '老牌五星酒店，服务、餐饮、卫生、环境都很赞，距离5号线淘金站，几乎零距离，特别适合家庭出游选择，会推荐给朋友。', '2024-02-19', 5, '[''整体满意度'', ''交通便利性'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236t12000d8sb8h42693_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233r12000d8seu0j1534_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231312000d8sfece6243_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '交通便利，就在地铁口。前台服务周到，房间有缺什么也是第一时间送到，5星服务很到位', '交通便利，就在地铁口。前台服务周到，房间有缺什么也是第一时间送到，5星服务很到位。还有自己的博物馆和后花园，入住体验感很好，下次还来，推荐', '2024-02-29', 5, '[''交通便利性'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232p12000db9x3tr8274_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235k12000db9pz7k818C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235u12000db9ysha4010_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店环境很美，前台给升级了套房，房间很大也很干净，很满意，春节氛围感很足，一直到', '酒店环境很美，前台给升级了套房，房间很大也很干净，很满意，春节氛围感很足，一直到初五都有年俗活动，服务态度很好。', '2024-02-16', 5, '[''整体满意度'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0231q12000d7xgxuq1EE5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店连住三晚，满意酒店位置，地铁公交打车都方便。酒店还有瀑布花园，博物馆，非常有', '酒店连住三晚，满意酒店位置，地铁公交打车都方便。酒店还有瀑布花园，博物馆，非常有特色。除了附近有工地，半夜时有噪音，其他都赞。', '2024-02-02', 5, '[''交通便利性'', ''周边配套'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231512000d40kdimC1F7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第一次入住花园酒店，高大上的感觉，特别四楼的【博物馆】相当的不错，赞??????', '第一次入住花园酒店，高大上的感觉，特别四楼的【博物馆】相当的不错，赞????????！瀑布餐厅的自助晚餐品种丰富，三文鱼柳，厚切的口感很过瘾！其他食材也不错，开启增肥的节奏！最感动的是，餐厅知道我生日，由经理携同祝贺团队一边唱着生日歌，一边送来了生日蛋糕和一支玫瑰花，暖暖的！可惜，客服后续服务跟不上！我在订房时已经明确需要加床，办理入住时再次重申要马上加床，一路颠簸很累！结果等了一个多小时，电话催了几次，才过来装上。感觉五星酒店不应该是这样的！', '2023-12-10', 4, '[''餐饮设施'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232k12000cpn8brr74F4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232a12000cpn8ayu9624_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235312000cpn84egB670_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234812000cpn84eu3121_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235812000cpn93k3A5F2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233m12000cpn94qpDDF0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '完全出乎意料的好！无论是设施服务还是饮食酒店文化都做的非常棒，新年入住气氛也很浓', '完全出乎意料的好！无论是设施服务还是饮食酒店文化都做的非常棒，新年入住气氛也很浓郁，体验很好，会再来。非常适合带孩子。', '2024-02-15', 5, '[''整体满意度'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235512000d7l6aaf7B0F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237012000d7l8ce0D436_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233912000d7l2r763D93_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '来广州首选花园酒店，入住时告诉接待员我们已是第三次入住，那位帅哥Kasas非常专', '来广州首选花园酒店，入住时告诉接待员我们已是第三次入住，那位帅哥Kasas非常专业和热情：“欢迎回家”，贴心地为我们升级了房间，赠送早餐和下午茶，太开心了，谢谢他。酒店的博物馆和老家俱展示都非常有特色，房间布置很漂亮，床品床单很高级的提花面料很舒服，也找服务员要了决明子枕头；打扫非常干净整洁；很慷慨的赠送饮用水；在酒店吃了荔湾亭和日料餐厅非常不错。', '2025-01-06', 5, '[''前台服务'', ''整体满意度'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232912000hmibx023195_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000hmi1sjsC2B1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233j12000hmidujy1316_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232a12000hmhscvy5759_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230612000hmhimcg8BBB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232612000hmhbvew7C70_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧是白金五星酒店，出入方便，在越秀区中心位置，环境优美，是酒店花园，家人都觉得', '不愧是白金五星酒店，出入方便，在越秀区中心位置，环境优美，是酒店花园，家人都觉得满意，下次还会考虑入住哦。', '2024-02-18', 5, '[''整体满意度'', ''交通便利性'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0233l12000d8hgl6z2E0B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235d12000d8hgu4492B8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236c12000d8hbdzz4D84_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233q12000d8h6n3y5AD1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235e12000d8hfcxx4F52_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f12000d8h4nag394D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236x12000d8hb52i1408_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235g12000d8hbk52C85E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q12000d8hg42c8DEF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌五星酒店 房间小 卫生不错  行政餐厅早餐热菜不算太多  晚餐基本凉菜 随便', '老牌五星酒店 房间小 卫生不错  行政餐厅早餐热菜不算太多  晚餐基本凉菜 随便喝喝酒可以 味道一般 西点重磅蛋糕不错 可颂不太行 餐品要加强
  
服务生笑容可掬 有求必应 酒店4楼博物馆加分 很有情怀 亲切

家里老人比较喜欢 洗漱设施陈旧 房门木质变色 太破旧 需要翻新了。
 地理位置优越 淘金站去哪都方便
下次来广州 还会选择升级房间 看看如何', '2023-12-12', 4, '[''房间设施'', ''餐饮设施'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0233v12000cq1f6k81EE6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235i12000cq1h15jD4EB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233812000cq1jwng7F32_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232612000cq1k7nb477D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务非常热情，楼层都有管家，微笑服务。房间打扫及时，干净，有欢迎水果送想得很周到', '服务非常热情，楼层都有管家，微笑服务。房间打扫及时，干净，有欢迎水果送想得很周到。桃园餐厅的菜品不错，没有低消。酒店出行很方便门口就是地铁。', '2024-01-27', 5, '[''前台服务'', ''客房服务'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0233612000d258rbdE31B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235g12000d258qd27027_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233912000d258rxqDB80_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232f12000d258ryh35AF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '每间夜含2位行政礼遇（含下午茶及欢乐时光）：非常满意！服务很贴心，因为是一个人入', '每间夜含2位行政礼遇（含下午茶及欢乐时光）：非常满意！服务很贴心，因为是一个人入住所以都是邀请朋友来happy hour，有一天多了一个朋友过来坐也能理解。下午茶点心很精致，只是晚了就会没有太多选择。
早餐: 早餐西餐种类较多，中餐选择相对较少，希望可以多一些本地早茶点心。', '2023-12-22', 5, '[''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231v324x8tlm7dwqBD8E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233y324x8tlg9l7y7998_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店服务、环境真的很棒，感谢行政走廊Tina、Echo、Kitty的优质服务，感', '酒店服务、环境真的很棒，感谢行政走廊Tina、Echo、Kitty的优质服务，感谢客房整理员陶美芳的细心服务。只要客房设施陈旧了些，期待早日修缮，期待下次再来住??', '2024-08-30', 4, '[''前台服务'', ''客房服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232i12000fbdo6vgCC6B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232s12000fbdymp5F869_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232212000fbdnw81EB21_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230512000fbdxyp70692_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233112000fbdu60e3ED3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '入住办理太费劲，人员效率慢，服务态度比较一般，对不起花园酒店这个名字，希望有待改', '入住办理太费劲，人员效率慢，服务态度比较一般，对不起花园酒店这个名字，希望有待改善，毕竟花园酒店是广州人的美好记忆。', '2024-02-09', 4, '[''前台服务'', ''退房/入住效率'']', '["[ \"https://dimg04.c-ctrip.com/images/0231k12000d60sluvE081_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234t12000d60f51qB6A6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230z12000d60mhrrEE7B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '位置好、规模大，是一家非常有文化底蕴的酒店，但设施设备很有年代感了，服务还是不错', '位置好、规模大，是一家非常有文化底蕴的酒店，但设施设备很有年代感了，服务还是不错的  春节期间大厅集市很有特色。', '2024-02-13', 4, '[''整体满意度'', ''周边配套'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231712000d6v8xht7366_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230s12000d6v7lhx6AB4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233512000d6uihbeB31D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236q12000d6v4wx14788_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236212000d6ufjk6C43A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间挺好的，环境不错，服务也好，酒店大气，有花园，花园里有许多锦鲤鱼，还有人造瀑', '房间挺好的，环境不错，服务也好，酒店大气，有花园，花园里有许多锦鲤鱼，还有人造瀑布，循环水溪，花园溜达也很惬意。不愧为花园酒店。值得推荐。', '2024-04-11', 5, '[''整体满意度'', ''公共设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231112000dncp6dhE422_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233b12000dncoz8g9882_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236v12000dncoz8o2ADB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235r12000dncp0e15574_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233y12000dncpal878CF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '难得住宿我会写评论', '难得住宿我会写评论
感谢携程铂金会员 让我升级了房间
行政酒廊的服务真心不错
房间也很干净
服务员也很热情
最爱酒店花园里的鱼
小朋友玩了都不想离开', '2024-01-16', 5, '[''整体满意度'', ''客房服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0232j12000cy88vke00CC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235812000cy89stlAF9F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230112000cy8fkdkAF4D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店很美，瀑布餐厅可以看锦鲤小朋友超喜欢，酒店服务也很好，给前台betty点个赞', '酒店很美，瀑布餐厅可以看锦鲤小朋友超喜欢，酒店服务也很好，给前台betty点个赞??态度耐心，看我们两个小朋友给不了连在一起的房间，还给我们升了房。住的很舒心，早餐也好吃。房间打扫的超干净。唯一不足就是可能外国人多，酒店房间太冷了，空调调高也没用，后面把空调关了挺好。总体说非常非常值得一住。', '2024-11-14', 5, '[''整体满意度'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231012000go853zn150D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232b12000go85f6w4C39_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235t12000go7onr41E4C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000go7yvxr0AF5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧是老牌的白金级五星级酒店，从下车到达开始见到的每一个服务人员都非常热情，特别', '不愧是老牌的白金级五星级酒店，从下车到达开始见到的每一个服务人员都非常热情，特别是行政酒廊的 Carrie 和 Jaismine 为我们的下午茶和欢乐时光都提供了细致周到的服务，给全家包括老人和小孩都留下了难忘的回忆，谢谢。', '2024-01-31', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232p12000d3b8ksi7986_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230812000d3bawq8F675_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235u12000d3bbsic4A48_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230j12000d3bbsig24C5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232e12000d3bbjgo3670_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235r12000d3bbmrb5F00_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店位置方便，硬件条件好，前台免费升级房型，非常感谢！下次来广州还会选择入住', '酒店位置方便，硬件条件好，前台免费升级房型，非常感谢！下次来广州还会选择入住', '2024-03-16', 5, '[''整体满意度'', ''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236u12000dfhj7gi8626_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间干净卫生整齐，大堂富丽堂皇，像一座艺术殿堂，服务态度好。瀑布餐厅漂亮值得打卡', '房间干净卫生整齐，大堂富丽堂皇，像一座艺术殿堂，服务态度好。瀑布餐厅漂亮值得打卡，四楼博物馆讲述了中国酒店发展史。', '2024-02-13', 5, '[''卫生状况'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231m12000d6u36505CFA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230p12000d6toprk0444_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235z12000d6u0hkf84E0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '位置方便，房间虽然老旧，但面积很大，宽敞舒适，大厅恢宏气派，服务态度很好，窗外有', '位置方便，房间虽然老旧，但面积很大，宽敞舒适，大厅恢宏气派，服务态度很好，窗外有瀑布景观，酒店有博物馆文化底蕴深厚', '2024-04-24', 4, '[''景观/朝向'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235d12000drp5ry8E480_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231312000drp4xau020B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230x12000drp5pkv0AD4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '考虑到要自由行动，所以选了交通便利的酒店，酒店边上就是地铁入口超级方便。过年期间', '考虑到要自由行动，所以选了交通便利的酒店，酒店边上就是地铁入口超级方便。过年期间酒店里也装饰的非常喜庆！', '2024-02-20', 5, '[''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236712000d91d0431DC4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231i12000d91dqm3861E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230b12000d91djnmBE8C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间干净，整洁，酒店的服务人员服务态度非常好。行政酒廊的工作人员服务周到，热情，', '房间干净，整洁，酒店的服务人员服务态度非常好。行政酒廊的工作人员服务周到，热情，Kanchan和Deepa笑容满面，相关酒店服务需求都会马上回应及解决，客房服务的小天也是服务周到，房间服务人员尽心尽力，还特意写了小卡片进行跟进，这个酒店要给个大大的赞??', '2024-08-17', 5, '[''客房服务'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0234g12000f5kasxlE4F5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230912000f5kgce758B6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230b12000f5kk4kd096F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧是老牌五星酒店的品牌，环境优美，房间也不错，服务态度非常好，有求必应，特别是', '不愧是老牌五星酒店的品牌，环境优美，房间也不错，服务态度非常好，有求必应，特别是酒店后花园的环境真的是太漂亮啦，下次来广州还会住花园酒店。', '2024-01-19', 5, '[''整体满意度'', ''前台服务'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0203k12000cz9qumqC8D4_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0232812000cz9arcgBAC2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231h12000cz98pli70DC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232c12000cz98smiD338_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '五星级酒店，三星的水准，入住体验最差的一次，壮观的门面，不如在入住的房间内多下工', '五星级酒店，三星的水准，入住体验最差的一次，壮观的门面，不如在入住的房间内多下工夫，金玉其外，败絮其中。', '2024-02-15', 1, '[''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236j12000d7pg0yoBD69_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230n12000d7p4asqACC3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234412000d7p8o15D8F3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '地理位置好，就在大街上容易看见。', '地理位置好，就在大街上容易看见。
房间重新装修了，喜欢这个格调，也喜欢大浴缸。
我住在701，我的小伙伴住在1949，他订的房间有行政酒廊，我们俩一起去了好几回，Cherry,Ken,Yuki,Carrie他们给了我们俩很好的服务。非常感恩。', '2023-12-04', 5, '[]', '["[ \"https://dimg04.c-ctrip.com/images/0206p12000coekvutF903_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0236y12000coekh9kFA7E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232w12000coec38v526C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店的历史悠久，大堂的圣诞气氛很浓厚，房间也还是蛮大的，有大圆桌和沙发，床上', '花园酒店的历史悠久，大堂的圣诞气氛很浓厚，房间也还是蛮大的，有大圆桌和沙发，床上用品比较舒服，上30楼餐厅的电梯不太人性化，如果不是4部直达电梯的话就要往下坐到一楼再转；因为需要小朋友的拖鞋和浴衣，礼宾部的电话打了几次才有人接；因为在房间里面看到游泳池在布置婚礼，特意打电话问前台游泳池是不是关闭了，前台在没有确定的情况下就说没有关闭，就带着小孩穿着泳衣下去了，泳池的前台又说游泳池今天有活动不开放了，这么冷的天，又带小孩回房间了，行政酒廊的食物种类特别少，基本上是住过的五星酒店里最少的，欢乐时光的食品还没有希尔顿的下午茶种类丰富，估计是花园酒店不是国际连锁，不需要维护会员的忠诚度吧，但是味道还是不错的，行政酒廊的工作人员Carrie,Ken,Yuki也是特别的热情和专业。退房的时候开车出车库，显示要交144元停车费，可是刚刚才在礼宾部报备了车牌号啊，后面还有一堆车在等，比较狼狈。', '2023-12-03', 4, '[''前台服务'', ''公共设施'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236512000co9ho9k42F1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230a12000co9jn4y8CDD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231012000co9h9qu2851_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间和服务都不错。桃园馆中餐厅环境优雅。只是位于30楼的下午茶太差了，无论是出品', '房间和服务都不错。桃园馆中餐厅环境优雅。只是位于30楼的下午茶太差了，无论是出品还是格局都与酒店的档次极不相称，体验感太差，实在可惜了！', '2024-01-20', 5, '[''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232v12000czdax510AC2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236f12000czdax5988D5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235s12000czdb0dh8504_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236o12000czdb0djF5ED_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '下午三点多办理入住的，人不多，等一两个就可以，不过办理过程稍微慢了一点点，花了十', '下午三点多办理入住的，人不多，等一两个就可以，不过办理过程稍微慢了一点点，花了十几分钟.小姐姐也一直在说不好意思，最后对房间还是满意的，应该是房间没清洁好临时给升了一个房型，然后比较安静没有受到附近施工??噪音的困扰.

 外观大堂都是老牌酒店的样子，内部重修装修过所以特别舒适大方.', '2023-12-06', 5, '[''退房/入住效率'', ''安静程度'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232y12000cou1lzm0BF5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233y12000cou3irf3641_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230p12000cotxq9xE068_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '岭南文化主题的酒店。', '岭南文化主题的酒店。
第二次在过年期间入住了，氛围感满满。春节期间酒店还有各种规定，大人小孩都玩得很开心…', '2024-02-11', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233g12000d6ejvr523FB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230x12000d6f82jwBB61_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店服务态度很好，周边交通很便利，出门就是地铁站，离点都德也很近，酒店春节期间各', '酒店服务态度很好，周边交通很便利，出门就是地铁站，离点都德也很近，酒店春节期间各种活动，很喜庆，人气旺！', '2024-02-11', 5, '[''交通便利性'', ''周边配套'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233312000d6f95yu98D3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235v12000d6fobupC833_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233712000d6fp8k93EF2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店设施服务很好', '酒店设施服务很好', '2024-05-16', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230d12000e0yn2mpF22B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务比以前好多了，二楼也很好吃。唯一缺点就是床太软了不适合有腰椎问题的老人家，希', '服务比以前好多了，二楼也很好吃。唯一缺点就是床太软了不适合有腰椎问题的老人家，希望酒店可以准备一些加硬的薄床垫。总体环境卫生服务用餐体验都很好。', '2024-01-10', 5, '[''房间设施'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230712000cwjnft75B72_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230z12000cwjvisk1ADD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232w12000cwjoozv6FF3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234k12000cwk0wq7F815_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235i12000cwjqbb1B7B4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '订了三间还升级了两间，价钱上是五星级里比较具有性价比的了，地理位置就在淘金，离地', '订了三间还升级了两间，价钱上是五星级里比较具有性价比的了，地理位置就在淘金，离地铁口也很近，去动物园两站路就可以了。', '2024-04-22', 5, '[''性价比'', ''交通便利性'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0235q12000dqzkisa978F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233e12000dqzlngc110F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233712000dqzlasb7D1A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间非常棒，cheek in的时间订的房间没有了，直接给我们升了房型。', '房间非常棒，cheek in的时间订的房间没有了，直接给我们升了房型。
酒店内的后花园和瀑布很漂亮。
还可以打电话到前台订专属导游，带着逛并介绍花园酒店。', '2024-03-08', 5, '[''前台服务'', ''整体满意度'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235s12000ddaa0t1547B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236k12000dda79md5CB6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235x12000dd9l46s5609_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230t12000dd9n4n3120C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233012000dd9mw7u1CDA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234812000dd9jhwy1778_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231o12000dd9n3td84DE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230y12000dd9hfj6F741_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230c12000dd9v2a73926_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '大促时购买了红棉大床房，其实本来想要双床房，结果订错了，check in时和前台', '大促时购买了红棉大床房，其实本来想要双床房，结果订错了，check in时和前台小姐姐沟通一番，小姐姐不仅二话不说帮我换了双床房还帮我升房了，升成了说是新装修的粤韵。确实设施都比较新，但是美中不足的是特地带了浴球来泡澡，结果粤韵房间是没有浴缸的，有点小小遗憾~
体验了花园酒店的三个餐厅，瀑布餐厅，荔湾亭和锦鲤酒吧。瀑布餐厅可以看到花园酒店瀑布全景，阳光洒落在落地窗上，听着瀑布声吃早餐很惬意~就是早餐的种类并不多，可能是本身餐厅不是很大的缘故吧…
荔湾亭的菜色很普通，和在外面的粤菜店其实差不多，性价比并不高。而且在五星酒店里的都要收服务费的情况下，我们事先询问了可以挂酒店房间的账，而且之前的服务员也询问了房间号，结果一位中年女服务员在我们还没离开店的时候语气并不耐烦的大声问同伴，问我们的账结了没有，周遭都很安静的在吃饭，结果这样一弄搞得我们仿佛在吃霸王餐？而且这位服务员上菜也是带着不耐烦的上的，碗碟敲得砰砰响，不知道有什么不开心的事，这种服务态度还要收服务费的话确实并不值得吧。
锦鲤酒吧我们20点30以后到的还有乐队驻唱，座位也是沙发座可以坐在一起聊天，氛围很好，服务员推荐了特色鸡尾酒，蓉和一个宾治都很好喝~
酒店客房部的人员都很耐心有礼，花园酒店还有自己的博物馆，可以提前预约讲解，lisa小姐姐讲的很生动人也好美丽~为她打call~??', '2023-11-30', 5, '[''前台服务'', ''餐饮设施'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231n12000cnnczux7974_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230e12000cnnifky8163_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230x12000cnn4oliED8E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233712000cnni8d043B4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店大堂装扮的非常喜庆，有舞龙舞狮表演，房间还有水果小吃赠送，服务员都非常热情，', '酒店大堂装扮的非常喜庆，有舞龙舞狮表演，房间还有水果小吃赠送，服务员都非常热情，就是酒店实在太老旧了。', '2024-02-11', 5, '[''整体满意度'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236012000d6hme8xD28B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000d6i0jgz1D03_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237012000d6hyesv807F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236212000d6i1s9c8433_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '今后四十年的历史发展，酒店经历过一次客房升级但时至今日过去些年日客房室内还是稍显', '今后四十年的历史发展，酒店经历过一次客房升级但时至今日过去些年日客房室内还是稍显老态，由于全地毯铺设的原因一开始进屋有些许霉味，空调开了一会会好一点。虽是老酒店但酒店的床垫非常舒适支撑性很好，柔软度也高这个一点非常棒。选择入住这家酒店不单单只是客房的体验，更是为了来见证感受这家富有传奇色彩的酒店，邓公的题字，建筑设计大师贝老参与的酒店设计将结构美学与实用性应用到了极致，Y型建筑设计 使空间得到了极大的使用同时兼顾了每个房间的采光和视野 是一个了不起的设计。这趟酒店之旅不需此行，值得体验。', '2023-11-14', 4, '[''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235d12000ckmqlpy8B1A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236012000ckmqehlC273_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234m12000ckmrjgzF77D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000ckmvk1h2AB9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230512000ckmrmp6CCCF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234v12000ckmuvsf3328_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231z12000ckmru10A045_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232t12000ckmvk1j017D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f12000ckmloy3CBC6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一家酒店可以看到改革开放的发展史，贝律铭的设计初稿，邓小平的题字，***的奠基，', '一家酒店可以看到改革开放的发展史，贝律铭的设计初稿，邓小平的题字，***的奠基，***的进口设备申请。酒店38年的历程里记录了太多的历史瞬间。
      原本冲着酒店的人文氛围去的，果然一到就发现值得打卡的地方甚多，自带的博物馆和mini画展也可以去看看。沁春园的锦鲤仿佛通灵一般，能与人亲热互动。
      由于抵达当天已近半夜，前台办理入住很慢，提前电话预约的房间预留完全没有作用（酒店热线的接线人员一问三不知，提出的合理要求都很勉强记录），安排在5楼完全不是协议中写的18到21层。房间设备也比较老旧，体验感比较差。第2天再三要求下换到19楼，可惜订的双床房变大床房，孩子爸爸睡不下了。房间安排上的混乱与拖延，这一点真的是让人无语。
      总体来说，酒店服务人员都是礼貌热情的，虽然业务能力不强，但还是给人宾至如归的感觉。由于正值中秋节，酒店也很应景地给客人准备了一盒??。除却客房安排和房间老旧有所欠缺外，还是值得入住的。', '2023-10-05', 4, '[''前台服务'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230u12000cbvjwj01B30_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232t12000cbvgtwaD7C5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233312000cbvbnujE9A0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231a12000cbvdy5e3BC2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236y12000cbvccceA3A1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235k12000cbveox748CB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235x12000cbvfhd366B8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233s12000cbvjy4oEC00_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235212000cbvd22vCD45_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '住店很舒服，很喜欢接待我们的前台小姐姐，说话温柔，给我们很温暖的感觉。酒店的后花', '住店很舒服，很喜欢接待我们的前台小姐姐，说话温柔，给我们很温暖的感觉。酒店的后花园也很棒，景色优美，如果能登小瀑布就更好了。', '2024-01-31', 5, '[''前台服务'', ''景观/朝向'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230512000d36ri9d7966_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店大堂富丽堂皇，后花园也非常漂亮，服务态度好，卫生干净，唯一不足就是房间稍微小', '酒店大堂富丽堂皇，后花园也非常漂亮，服务态度好，卫生干净，唯一不足就是房间稍微小了一点，总体感受还是不错，值得入住', '2024-02-13', 5, '[''整体满意度'', ''卫生状况'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233812000d6vdxyq9609_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230d12000d6v5fr34138_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233m12000d6vf1dc4EF3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235a12000d6vft6e42CB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235q12000d6ve54sAE2F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '作为携程的铂金会员升级了岭客汇的金卡，入住时升级了粤韵大床，因为才刚装修完没几年', '作为携程的铂金会员升级了岭客汇的金卡，入住时升级了粤韵大床，因为才刚装修完没几年，环境自然是可以，且楼层服务员打扫房间很及时。但是花园大床房就不建议入住了，一进去房间就一股异味。早餐是在30楼用餐，品种较少，行政酒廊下午茶点心选择性也较少。游泳池是常温的，现在这个季节下水还是有点冷的。', '2023-11-28', 4, '[''房间设施'', ''餐饮设施'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232512000cndbbpq628B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235o12000cndb99kF74A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231c12000cnddi9k28CA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230g12000cndbgzqCD8C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230712000cndl40d5F0C_R_150_150_R5_Q70_D.jpg\" ]"]');